const topics = [
  "Spring Bass Fishing Shallow Water Tactics",
  "Summer Pike Fishing Best Lures",
  "Fall Trout Fishing Where to Find Them",
  "Winter Walleye Ice Fishing Tips",
  "Top 5 Crankbaits for Muddy Water Bass",
  "Mastering the Drop Shot Rig",
  "Saltwater Fishing Reading Tides",
  "Trophy Muskie Proven Techniques",
  "Fly Fishing Basics for Beginners",
  "Night Catfish Fishing Complete Guide",
  "Essential Fishing Knots Every Angler Needs",
  "Reading Water Find Fish Like a Pro",
  "Seasonal Bait Selection Guide",
  "Using Fish Finders Effectively",
  "Panfish Crappie and Bluegill Tips"
];

const manualTopic = $input.item.json.body?.topic || $input.item.json.topic;
const now = new Date();
const week = Math.ceil((now - new Date(now.getFullYear(), 0, 1)) / 604800000);

return {
  json: {
    topic: manualTopic || topics[week % topics.length],
    episode: week,
    date: now.toISOString().split('T')[0]
  }
};

const raw = $input.item.json.response;
const topic = $node['Select Topic'].json;

// Clean script
const script = raw
  .replace(/\[INTRO.*?\]/gi, '')
  .replace(/\[MAIN.*?\]/gi, '')
  .replace(/\[PRODUCT.*?\]/gi, '')
  .replace(/\[OUTRO.*?\]/gi, '')
  .replace(/\*\*/g, '')
  .replace(/\*/g, '')
  .trim();

const words = script.split(/\s+/).length;
const minutes = Math.ceil(words / 150);

return {
  json: {
    episode_number: topic.episode,
    topic: topic.topic,
    date: topic.date,
    script: script,
    word_count: words,
    duration: minutes,
    title: `Episode ${topic.episode}: ${topic.topic}`
  }
};

const script = $node['Parse Script'].json;
let showNotes = '';
try {
  showNotes = $node['Generate Show Notes']?.json?.response || 'Show notes pending...';
} catch (e) {
  showNotes = 'Show notes generation in progress...';
}

// Get audio data from SSH output
let audioSize = 0;
let hasAudio = false;
try {
  const sshOutput = $node['Generate Audio (Ryan High)'].json;
  if (sshOutput && sshOutput.stdout) {
    // Parse base64 from SSH output between markers
    const match = sshOutput.stdout.match(/===AUDIO_START===\n([\s\S]*?)===AUDIO_END===/);
    if (match && match[1]) {
      const audioBase64 = match[1].trim();
      audioSize = Buffer.from(audioBase64, 'base64').length;
      hasAudio = true;
    }
  }
} catch (e) {
  hasAudio = false;
}

return {
  json: {
    episode_number: script.episode_number,
    title: script.title,
    topic: script.topic,
    date: script.date,
    duration_minutes: script.duration,
    full_script: script.script,
    show_notes: showNotes,
    word_count: script.word_count,
    audio_generated: hasAudio,
    audio_size_kb: Math.round(audioSize / 1024),
    created_at: new Date().toISOString(),
    created_by: 'Perry AI Podcast Generator',
    status: 'ready_to_publish',
    store_url: 'https://shorettesbaitandtackle.myshopify.com',
    podcast_url: `https://shorettesbaitandtackle.com/podcast/episode-${script.episode_number}`
  }
};
